INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04880', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '帕波爾與樓斯門（Papell and Rothman）認為團體工作三大模型，下列何者錯誤？', '["社會目標模型（social goals model）中心概念是社會意識（social consciousness）和社會責任（social responsibility）", "治療模型（remedial model）將團體視為一種治療工具，工作者是使能者（enabler），案主則 是受苦於某種適應不良的結果", "互惠模型（reciprocal model）在助人過程的焦點是個人和社會", "團體是互惠模型的中心，團體是團體工作者心中的案主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04881', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關臺灣早期社會團體工作發展，下列何者錯誤？', '["臺灣的社會團體工作發展與社會個案工作的發展差不多", "早期團體工作師資與相關書籍之缺乏，以及實務工作者因訓練不足，導致早期團體工作發展緩慢", "實務工作者對團體工作的不熟悉，和以青年工作為主的社會服務機構使用了輔導取向的團體技 巧，造成團體工作與團體輔導概念運用上的混淆", "早期基督教青年會及救國團的青年服務，對臺灣的社會團體工作有催生的作用和貢獻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04882', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對團體工作的敘述，何者錯誤？', '["有學者認為效能、適用性和具成本效益為團體工作主要之優點", "受限於時間的考量，團體工作似乎成為較佳的工作模式", "和個別工作不同，團體工作提供「同儕的投入、多重意見的回饋、有效運用帶領工作者的時間， 以及旁觀學習」", "有診斷標準的具體問題領域，例如：哀傷治療、物質濫用、飲食失調及童年遭受性虐待，對這 些特定族群和問題／議題而言，個別處遇可能更為適合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04883', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列敘述何者是「假性團體」的定義？', '["團體成員被指派一起工作，但是他們卻對工作毫無興趣", "團體成員同意一起工作，但是很少從團體中獲益", "團體不只是成員的組合，且各個成員投注極大的心力，以達成個人目標和團體目標", "團體的個人目標重於團體互惠的目標，互動是中立的，團體個人身分重於成員的身分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04884', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '自我（self）在社會化的歷程中，下列那些特徵是相當關鍵的？①自我知覺是一種心理性的獲得，', '["自我的產生源自多重的來源，而非單一的事件", "同一來源在不同的時間點，對 個人亦可能蘊含不同的意義", "自我概念源自社會歷程，而且是一個持續一生不停止建構的歷程", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04885', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '場域理論（field theory）重要概念，請選出所有正確答案：①場域  ②需求  ③目標  ④張力 ⑤生態系統', '["僅", "", "", "⑤"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04886', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關交換理論（exchange theory）的敘述，下列何者錯誤？', '["社會交換的概念在建構社會行為的研究上會是有用的開始", "交換理論人際運作假設，源自於人類學、心理學、經濟學和遊戲理論的運用", "交換理論詮釋人們為了獲得生活所需，必須與他人交易、交換，並形成穩定關係的歷程", "Homans認為社會交換概念可以解釋所有人類行為的現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04887', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作開始階段的工作重點和工作目標，下列何者正確？①建立團體規範  ②加強正向動', '["處理團體成員參與的問題", "處理成員之間的衝突與緊張  ⑤創造安全與信任 關係  ⑥發展溝通、地位、角色與規範的彈性結構  ⑦協助成員感覺自己是團體的一份子  ⑧穩 定成員的參與及團體的運作", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04888', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體結束階段的敘述，下列何者不適當？', '["在Kubler-Ross 研究中面對死亡悲傷的反應也會出現在此階段成員的情緒表現", "領導者在此階段應該儘早與成員劃清界線，避免成員依賴領導者", "提前預告團體結束會有助於降低離別情緒", "鞏固所學可以堅定成員成長獨立的勇氣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04889', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關接案（intake）會談的敘述，下列何者正確？', '["進行接案會談時，還不確定接下來是否開案，因此社會工作者尚無須與潛在個案建立專業關係", "進行接案會談時，若社會工作者發現個案的需求不在機構所提供的服務範圍內，須向潛在個案 說明理由，但無須做成紀錄", "進行接案會談時，若社會工作者發現機構的服務無法回應潛在個案的問題性質，則須提供潛在 個案充分的社會資源資訊，或提供轉介服務", "進行接案會談時，為避免潛在個案自我標籤為「失敗者」，社會工作者應減少在此階段運用同 理心的技巧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "6f22bcf6b5fd", "answer_pdf_sha1": "cdfe8297aa37", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
